// 計算今日 metrics + 7 天均值 + 異常偵測
const GEMINI_API_KEY = '__GEMINI_API_KEY__';

// 今日數據（input 來自 Extract 今日 CSV）
const todayItems = $('Extract 今日 CSV').all();
const today = {};
for (const it of todayItems) {
  const m = it.json.metric;
  const v = parseFloat(it.json.value);
  if (m && !isNaN(v)) today[m] = v;
}

// 歷史數據
const histItems = $('Extract 歷史 CSV').all();
const histByMetric = {};
for (const it of histItems) {
  const m = it.json.metric;
  const v = parseFloat(it.json.value);
  if (m && !isNaN(v)) {
    if (!histByMetric[m]) histByMetric[m] = [];
    histByMetric[m].push(v);
  }
}

// 計算 7 天均值 + 偏差
const metrics = [];
const anomalies = [];
for (const [m, v] of Object.entries(today)) {
  const hist = histByMetric[m] || [];
  const avg = hist.length > 0 ? hist.reduce((s, x) => s + x, 0) / hist.length : null;
  const max = hist.length > 0 ? Math.max(...hist) : null;
  const min = hist.length > 0 ? Math.min(...hist) : null;
  const deviation = avg !== null ? ((v - avg) / avg * 100) : null;
  const entry = { metric: m, today: v, avg7d: avg, max7d: max, min7d: min, deviation };
  metrics.push(entry);
  if (deviation !== null && Math.abs(deviation) > 30) anomalies.push(entry);
}

const dateKey = new Date().toISOString().slice(0, 10);
let aiSummary = '';
if (anomalies.length > 0) {
  const prompt = '你是營運分析助手。下面是今日指標相對 7 天均值的異常（偏差 > 30%）。請用 3 句話分析：(1) 哪些異常最重要 (2) 可能原因 (3) 建議下一步動作。繁中。\n\n<異常>\n' + JSON.stringify(anomalies) + '\n</異常>';
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
      body: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.4, maxOutputTokens: 400, thinkingConfig: { thinkingBudget: 0 } }
      },
      json: true,
      timeout: 30000
    });
    aiSummary = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  } catch (err) {}
}

const snapshot = { date: dateKey, today, metrics, anomalies, aiSummary, generatedAt: new Date().toISOString() };

const tgMsg = anomalies.length === 0
  ? '✅ 今日營運快照（' + dateKey + '）\n\n' + metrics.map(m => '· ' + m.metric + '：' + m.today + (m.avg7d ? '（7d avg ' + m.avg7d.toFixed(1) + '）' : '')).join('\n') + '\n\n所有指標都在正常範圍。'
  : '🚨 今日異常 ' + anomalies.length + ' 項（' + dateKey + '）\n\n' + anomalies.map(a => '· ' + a.metric + '：' + a.today + ' vs avg ' + a.avg7d.toFixed(1) + ' (' + (a.deviation > 0 ? '+' : '') + a.deviation.toFixed(1) + '%)').join('\n') + '\n\n📊 AI 分析：\n' + aiSummary;

return [{
  json: { snapshot, tgMsg, snapshotPath: '/files/shared/ops-snapshots/snapshot-' + dateKey + '.json' },
  binary: {
    data: { data: Buffer.from(JSON.stringify(snapshot, null, 2)).toString('base64'), mimeType: 'application/json', fileName: 'snapshot-' + dateKey + '.json' }
  }
}];
